@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun LensDetailScreen(
    navController: NavController,
    vm: LensDetailViewModel = viewModel(),
) {
    val state by vm.state.collectAsStateWithLifecycle()

    var showDiscardDialog by remember { mutableStateOf(false) }
    var showDeleteDialog by remember { mutableStateOf(false) }

    LaunchedEffect(Unit) {
        vm.events.collect { event ->
            when (event) {
                LensDetailEvent.SaveSuccessful -> navController.popBackStack()
                LensDetailEvent.DeleteSuccessful -> navController.popBackStack()
                LensDetailEvent.ConfirmDiscard -> showDiscardDialog = true
            }
        }
    }

    val isEditMode = state.id != 0
    val title = if (isEditMode) "Edit Lens" else "New Lens"

    val navigateBack: () -> Unit = {
        if (!state.isDirty) navController.popBackStack()
        else vm.onBackPressed()
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(title) },
                navigationIcon = {
                    IconButton(onClick = navigateBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                },
                actions = {
                    if (isEditMode) {
                        IconButton(onClick = { showDeleteDialog = true }) {
                            Icon(Icons.Default.Delete, contentDescription = "Delete lens")
                        }
                    }
                    TextButton(
                        onClick = vm::onSaveTapped,
                        enabled = !state.isSaving,
                    ) {
                        Text("Save")
                    }
                },
            )
        },
    ) { innerPadding ->

        if (state.isLoading) {
            Box(
                modifier = Modifier.fillMaxSize().padding(innerPadding),
                contentAlignment = Alignment.Center,
            ) {
                CircularProgressIndicator()
            }
            return@Scaffold
        }

        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .verticalScroll(rememberScrollState())
                .padding(horizontal = 16.dp, vertical = 8.dp),
        ) {
            // Name
            OutlinedTextField(
                value = state.name,
                onValueChange = vm::onNameChanged,
                label = { Text("Name *") },
                placeholder = { Text("e.g. 50mm f/1.4 Summilux") },
                isError = state.nameError != null,
                supportingText = state.nameError?.let { { Text(it) } },
                singleLine = true,
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
            )

            // Make
            OutlinedTextField(
                value = state.make,
                onValueChange = vm::onMakeChanged,
                label = { Text("Make *") },
                placeholder = { Text("e.g. Leitz") },
                isError = state.makeError != null,
                supportingText = state.makeError?.let { { Text(it) } },
                singleLine = true,
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
            )

            // Focal length
            OutlinedTextField(
                value = state.focalLengthMm,
                onValueChange = vm::onFocalLengthChanged,
                label = { Text("Focal length (mm) *") },
                placeholder = { Text("e.g. 50") },
                isError = state.focalLengthError != null,
                supportingText = state.focalLengthError?.let { { Text(it) } },
                singleLine = true,
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
            )

            // Mount type — autocomplete from existing lens mounts
            MountTypeField(
                value = state.mountType,
                onValueChange = vm::onMountTypeChanged,
                suggestions = state.mountTypeSuggestions,
                isError = state.mountTypeError != null,
                errorMessage = state.mountTypeError,
            )

            // Max aperture (widest — smallest f-number)
            OutlinedTextField(
                value = state.maxAperture,
                onValueChange = vm::onMaxApertureChanged,
                label = { Text("Maximum aperture *") },
                placeholder = { Text("e.g. 1.4") },
                prefix = { Text("f/") },
                isError = state.maxApertureError != null,
                supportingText = state.maxApertureError?.let { { Text(it) } },
                singleLine = true,
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
            )

            // Min aperture (narrowest — largest f-number)
            OutlinedTextField(
                value = state.minAperture,
                onValueChange = vm::onMinApertureChanged,
                label = { Text("Minimum aperture *") },
                placeholder = { Text("e.g. 16") },
                prefix = { Text("f/") },
                isError = state.minApertureError != null,
                supportingText = state.minApertureError?.let { { Text(it) } },
                singleLine = true,
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
            )

            // Aperture increments picker
            EnumDropdown(
                label = "Aperture increments *",
                options = ApertureIncrements.entries,
                selected = state.apertureIncrements,
                onSelected = vm::onApertureIncrementsChanged,
                displayName = { it.label },
            )

            // Filter size (optional)
            OutlinedTextField(
                value = state.filterSizeMm,
                onValueChange = vm::onFilterSizeChanged,
                label = { Text("Filter size (mm)") },
                placeholder = { Text("e.g. 49") },
                suffix = { Text("mm") },
                singleLine = true,
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
            )

            // Notes
            OutlinedTextField(
                value = state.notes,
                onValueChange = vm::onNotesChanged,
                label = { Text("Notes") },
                minLines = 3,
                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
            )
        }
    }

    // Discard changes dialog
    if (showDiscardDialog) {
        AlertDialog(
            onDismissRequest = { showDiscardDialog = false },
            title = { Text("Discard changes?") },
            text = { Text("Your unsaved changes will be lost.") },
            confirmButton = {
                TextButton(onClick = { navController.popBackStack() }) {
                    Text("Discard")
                }
            },
            dismissButton = {
                TextButton(onClick = { showDiscardDialog = false }) {
                    Text("Keep editing")
                }
            },
        )
    }

    // Delete confirmation dialog
    if (showDeleteDialog) {
        AlertDialog(
            onDismissRequest = { showDeleteDialog = false },
            title = { Text("Delete lens?") },
            text = { Text("This lens will be permanently deleted. This cannot be undone.") },
            confirmButton = {
                TextButton(onClick = { vm.onDeleteConfirmed(); showDeleteDialog = false }) {
                    Text("Delete")
                }
            },
            dismissButton = {
                TextButton(onClick = { showDeleteDialog = false }) {
                    Text("Cancel")
                }
            },
        )
    }
}

// ---------------------------------------------------------------------------
// Shared field composables — reused across gear detail screens
// ---------------------------------------------------------------------------

/**
 * Mount type text field with type-ahead autocomplete from existing lens mount types.
 * Suggestions are filtered as the user types. The user can enter any free-form value.
 */
@OptIn(ExperimentalMaterial3Api::class)
@Composable
internal fun MountTypeField(
    value: String,
    onValueChange: (String) -> Unit,
    suggestions: List<String>,
    isError: Boolean,
    errorMessage: String?,
    label: String = "Mount type *",
    modifier: Modifier = Modifier,
) {
    val filtered = remember(value, suggestions) {
        suggestions.filter { it.contains(value, ignoreCase = true) && it != value }
    }
    var expanded by remember { mutableStateOf(false) }

    ExposedDropdownMenuBox(
        expanded = expanded && filtered.isNotEmpty(),
        onExpandedChange = { expanded = it },
        modifier = modifier.fillMaxWidth().padding(vertical = 4.dp),
    ) {
        OutlinedTextField(
            value = value,
            onValueChange = { onValueChange(it); expanded = true },
            label = { Text(label) },
            placeholder = { Text("e.g. M-mount, EF, F") },
            isError = isError,
            supportingText = errorMessage?.let { { Text(it) } },
            singleLine = true,
            modifier = Modifier
                .fillMaxWidth()
                .menuAnchor(MenuAnchorType.PrimaryEditable, true),
        )
        ExposedDropdownMenu(
            expanded = expanded && filtered.isNotEmpty(),
            onDismissRequest = { expanded = false },
        ) {
            filtered.forEach { suggestion ->
                DropdownMenuItem(
                    text = { Text(suggestion) },
                    onClick = { onValueChange(suggestion); expanded = false },
                    contentPadding = ExposedDropdownMenuDefaults.ItemContentPadding,
                )
            }
        }
    }
}

/**
 * Read-only dropdown picker for enum values.
 * Used for ApertureIncrements, ShutterIncrements, CameraBodyFormat, etc.
 */
@OptIn(ExperimentalMaterial3Api::class)
@Composable
internal fun <T> EnumDropdown(
    label: String,
    options: List<T>,
    selected: T,
    onSelected: (T) -> Unit,
    displayName: (T) -> String,
    modifier: Modifier = Modifier,
) {
    var expanded by remember { mutableStateOf(false) }

    ExposedDropdownMenuBox(
        expanded = expanded,
        onExpandedChange = { expanded = it },
        modifier = modifier.fillMaxWidth().padding(vertical = 4.dp),
    ) {
        OutlinedTextField(
            value = displayName(selected),
            onValueChange = {},
            readOnly = true,
            label = { Text(label) },
            trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expanded) },
            modifier = Modifier
                .fillMaxWidth()
                .menuAnchor(MenuAnchorType.PrimaryNotEditable, true),
        )
        ExposedDropdownMenu(
            expanded = expanded,
            onDismissRequest = { expanded = false },
        ) {
            options.forEach { option ->
                DropdownMenuItem(
                    text = { Text(displayName(option)) },
                    onClick = { onSelected(option); expanded = false },
                    contentPadding = ExposedDropdownMenuDefaults.ItemContentPadding,
                )
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Enum display names used in gear detail screens
// ---------------------------------------------------------------------------

internal val ApertureIncrements.label: String
    get() = when (this) {
        ApertureIncrements.FULL -> "Full stops"
        ApertureIncrements.HALF -> "Half stops"
        ApertureIncrements.THIRD -> "Third stops"
    }

package com.southsouthwest.framelog.ui.gear

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.viewModelScope
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.entity.CameraBody
import com.southsouthwest.framelog.data.db.entity.CameraBodyFormat
import com.southsouthwest.framelog.data.db.entity.ShutterIncrements
import com.southsouthwest.framelog.data.repository.GearRepository
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class CameraBodyDetailUiState(
    val id: Int = 0,
    val name: String = "",
    val make: String = "",
    val model: String = "",
    val mountType: String = "",
    val format: CameraBodyFormat = CameraBodyFormat.THIRTY_FIVE_MM,
    val shutterIncrements: ShutterIncrements = ShutterIncrements.FULL,
    val notes: String = "",
    // Mount type autocomplete — sourced from existing Lens mount types
    val mountTypeSuggestions: List<String> = emptyList(),
    val isLoading: Boolean = false,
    val isSaving: Boolean = false,
    val isDirty: Boolean = false,
    val nameError: String? = null,
    val makeError: String? = null,
    val modelError: String? = null,
    val mountTypeError: String? = null,
)

sealed class CameraBodyDetailEvent {
    data object SaveSuccessful : CameraBodyDetailEvent()
    data object DeleteSuccessful : CameraBodyDetailEvent()
    data object ConfirmDiscard : CameraBodyDetailEvent()
}

class CameraBodyDetailViewModel(
    application: Application,
    savedState: SavedStateHandle,
) : AndroidViewModel(application) {

    private val bodyId: Int = savedState["id"] ?: 0
    private val gearRepository = GearRepository(AppDatabase.getInstance(application))

    private val _state = MutableStateFlow(CameraBodyDetailUiState(id = bodyId, isLoading = bodyId != 0))
    val state: StateFlow<CameraBodyDetailUiState> = _state.asStateFlow()

    private val _events = Channel<CameraBodyDetailEvent>(Channel.BUFFERED)
    val events: Flow<CameraBodyDetailEvent> = _events.receiveAsFlow()

    init {
        loadMountTypeSuggestions()
        if (bodyId != 0) loadExistingBody()
    }

    private fun loadMountTypeSuggestions() = viewModelScope.launch {
        // Lens is the vocabulary source for mount types; bodies pick from existing lens mounts.
        gearRepository.getDistinctMountTypes().collect { types ->
            _state.update { it.copy(mountTypeSuggestions = types) }
        }
    }

    private fun loadExistingBody() = viewModelScope.launch {
        gearRepository.getCameraBodyById(bodyId).collect { body ->
            _state.update {
                it.copy(
                    name = body.name,
                    make = body.make,
                    model = body.model,
                    mountType = body.mountType,
                    format = body.format,
                    shutterIncrements = body.shutterIncrements,
                    notes = body.notes ?: "",
                    isLoading = false,
                    isDirty = false,
                )
            }
            return@collect
        }
    }

    fun onNameChanged(value: String) =
        _state.update { it.copy(name = value, isDirty = true, nameError = null) }

    fun onMakeChanged(value: String) =
        _state.update { it.copy(make = value, isDirty = true, makeError = null) }

    fun onModelChanged(value: String) =
        _state.update { it.copy(model = value, isDirty = true, modelError = null) }

    fun onMountTypeChanged(value: String) =
        _state.update { it.copy(mountType = value, isDirty = true, mountTypeError = null) }

    fun onFormatChanged(value: CameraBodyFormat) =
        _state.update { it.copy(format = value, isDirty = true) }

    fun onShutterIncrementsChanged(value: ShutterIncrements) =
        _state.update { it.copy(shutterIncrements = value, isDirty = true) }

    fun onNotesChanged(value: String) =
        _state.update { it.copy(notes = value, isDirty = true) }

    fun onSaveTapped() = viewModelScope.launch {
        val s = _state.value
        if (!validate(s)) return@launch

        _state.update { it.copy(isSaving = true) }

        val body = CameraBody(
            id = bodyId,
            name = s.name.trim(),
            make = s.make.trim(),
            model = s.model.trim(),
            mountType = s.mountType.trim(),
            format = s.format,
            shutterIncrements = s.shutterIncrements,
            notes = s.notes.trim().ifBlank { null },
        )

        if (bodyId == 0) gearRepository.insertCameraBody(body)
        else gearRepository.updateCameraBody(body)

        _state.update { it.copy(isSaving = false, isDirty = false) }
        _events.send(CameraBodyDetailEvent.SaveSuccessful)
    }

    fun onDeleteConfirmed() = viewModelScope.launch {
        if (bodyId == 0) return@launch
        val s = _state.value
        val body = CameraBody(
            id = bodyId,
            name = s.name,
            make = s.make,
            model = s.model,
            mountType = s.mountType,
            format = s.format,
            shutterIncrements = s.shutterIncrements,
        )
        gearRepository.deleteCameraBody(body)
        _events.send(CameraBodyDetailEvent.DeleteSuccessful)
    }

    fun onBackPressed() = viewModelScope.launch {
        if (_state.value.isDirty) _events.send(CameraBodyDetailEvent.ConfirmDiscard)
    }

    private fun validate(s: CameraBodyDetailUiState): Boolean {
        var valid = true
        if (s.name.isBlank()) {
            _state.update { it.copy(nameError = "Name is required") }
            valid = false
        }
        if (s.make.isBlank()) {
            _state.update { it.copy(makeError = "Make is required") }
            valid = false
        }
        if (s.model.isBlank()) {
            _state.update { it.copy(modelError = "Model is required") }
            valid = false
        }
        if (s.mountType.isBlank()) {
            _state.update { it.copy(mountTypeError = "Mount type is required") }
            valid = false
        }
        return valid
    }
}

package com.southsouthwest.framelog.ui.gear

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.viewModelScope
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.entity.Filter
import com.southsouthwest.framelog.data.repository.GearRepository
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class FilterDetailUiState(
    val id: Int = 0,
    val name: String = "",
    val make: String = "",
    val filterType: String = "",
    /** String representation of the EV reduction; blank = null in DB. */
    val evReduction: String = "",
    /** String representation of the filter size in mm; blank = null in DB. */
    val filterSizeMm: String = "",
    val notes: String = "",
    // Autocomplete — existing filterType values from the database (folksonomy)
    val filterTypeSuggestions: List<String> = emptyList(),
    val isLoading: Boolean = false,
    val isSaving: Boolean = false,
    val isDirty: Boolean = false,
    val nameError: String? = null,
    val makeError: String? = null,
    val filterTypeError: String? = null,
    val evReductionError: String? = null,
)

sealed class FilterDetailEvent {
    data object SaveSuccessful : FilterDetailEvent()
    data object DeleteSuccessful : FilterDetailEvent()
    data object ConfirmDiscard : FilterDetailEvent()
}

class FilterDetailViewModel(
    application: Application,
    savedState: SavedStateHandle,
) : AndroidViewModel(application) {

    private val filterId: Int = savedState["id"] ?: 0
    private val gearRepository = GearRepository(AppDatabase.getInstance(application))

    private val _state = MutableStateFlow(FilterDetailUiState(id = filterId, isLoading = filterId != 0))
    val state: StateFlow<FilterDetailUiState> = _state.asStateFlow()

    private val _events = Channel<FilterDetailEvent>(Channel.BUFFERED)
    val events: Flow<FilterDetailEvent> = _events.receiveAsFlow()

    init {
        loadFilterTypeSuggestions()
        if (filterId != 0) loadExistingFilter()
    }

    private fun loadFilterTypeSuggestions() = viewModelScope.launch {
        gearRepository.getDistinctFilterTypes().collect { types ->
            _state.update { it.copy(filterTypeSuggestions = types) }
        }
    }

    private fun loadExistingFilter() = viewModelScope.launch {
        gearRepository.getFilterById(filterId).collect { filter ->
            _state.update {
                it.copy(
                    name = filter.name,
                    make = filter.make,
                    filterType = filter.filterType,
                    evReduction = filter.evReduction?.toString() ?: "",
                    filterSizeMm = filter.filterSizeMm?.toString() ?: "",
                    notes = filter.notes ?: "",
                    isLoading = false,
                    isDirty = false,
                )
            }
            return@collect
        }
    }

    fun onNameChanged(value: String) =
        _state.update { it.copy(name = value, isDirty = true, nameError = null) }

    fun onMakeChanged(value: String) =
        _state.update { it.copy(make = value, isDirty = true, makeError = null) }

    fun onFilterTypeChanged(value: String) =
        _state.update { it.copy(filterType = value, isDirty = true, filterTypeError = null) }

    fun onEvReductionChanged(value: String) =
        _state.update { it.copy(evReduction = value, isDirty = true, evReductionError = null) }

    fun onFilterSizeChanged(value: String) =
        _state.update { it.copy(filterSizeMm = value, isDirty = true) }

    fun onNotesChanged(value: String) =
        _state.update { it.copy(notes = value, isDirty = true) }

    fun onSaveTapped() = viewModelScope.launch {
        val s = _state.value
        if (!validate(s)) return@launch

        _state.update { it.copy(isSaving = true) }

        // Blank evReduction = no meaningful exposure effect (e.g. UV filter)
        val evFloat = s.evReduction.toFloatOrNull()

        val filter = Filter(
            id = filterId,
            name = s.name.trim(),
            make = s.make.trim(),
            filterType = s.filterType.trim(),
            evReduction = evFloat,
            filterSizeMm = s.filterSizeMm.toIntOrNull(),
            notes = s.notes.trim().ifBlank { null },
        )

        if (filterId == 0) gearRepository.insertFilter(filter)
        else gearRepository.updateFilter(filter)

        _state.update { it.copy(isSaving = false, isDirty = false) }
        _events.send(FilterDetailEvent.SaveSuccessful)
    }

    fun onDeleteConfirmed() = viewModelScope.launch {
        if (filterId == 0) return@launch
        val s = _state.value
        val filter = Filter(
            id = filterId,
            name = s.name,
            make = s.make,
            filterType = s.filterType,
            evReduction = s.evReduction.toFloatOrNull(),
            filterSizeMm = s.filterSizeMm.toIntOrNull(),
        )
        gearRepository.deleteFilter(filter)
        _events.send(FilterDetailEvent.DeleteSuccessful)
    }

    fun onBackPressed() = viewModelScope.launch {
        if (_state.value.isDirty) _events.send(FilterDetailEvent.ConfirmDiscard)
    }

    private fun validate(s: FilterDetailUiState): Boolean {
        var valid = true
        if (s.name.isBlank()) {
            _state.update { it.copy(nameError = "Name is required") }
            valid = false
        }
        if (s.make.isBlank()) {
            _state.update { it.copy(makeError = "Make is required") }
            valid = false
        }
        if (s.filterType.isBlank()) {
            _state.update { it.copy(filterTypeError = "Filter type is required") }
            valid = false
        }
        // evReduction is optional (blank = null); if provided it must be a positive number
        val ev = s.evReduction
        if (ev.isNotBlank()) {
            val f = ev.toFloatOrNull()
            if (f == null || f <= 0f) {
                _state.update { it.copy(evReductionError = "EV reduction must be a positive number (e.g. 3.0)") }
                valid = false
            }
        }
        return valid
    }
}

