import com.southsouthwest.framelog.data.db.entity.Roll
import com.southsouthwest.framelog.data.db.entity.RollStatus
import com.southsouthwest.framelog.data.repository.RollRepository
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.FlowPreview
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.debounce
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

// ---------------------------------------------------------------------------
// Tab enum
// ---------------------------------------------------------------------------

enum class RollListTab { ACTIVE, FINISHED, ARCHIVED }

// ---------------------------------------------------------------------------
// UiState
// ---------------------------------------------------------------------------

data class RollListUiState(
    val selectedTab: RollListTab = RollListTab.ACTIVE,
    val searchQuery: String = "",
    val activeRolls: List<Roll> = emptyList(),
    val finishedRolls: List<Roll> = emptyList(),
    val archivedRolls: List<Roll> = emptyList(),
    val isLoading: Boolean = true,
)

// ---------------------------------------------------------------------------
// Events
// ---------------------------------------------------------------------------

sealed class RollListEvent {
    data object NavigateToRollSetup : RollListEvent()
    data class NavigateToRollJournal(val rollId: Int) : RollListEvent()
    /** Emit to show the Load Roll confirmation sheet for [roll]. */
    data class ShowLoadConfirmation(val roll: Roll) : RollListEvent()
    /** Emit to show the delete danger confirmation for [roll]. */
    data class ShowDeleteConfirmation(val roll: Roll) : RollListEvent()
    data class ShowErrorMessage(val message: String) : RollListEvent()
}

// ---------------------------------------------------------------------------
// ViewModel
// ---------------------------------------------------------------------------

@OptIn(ExperimentalCoroutinesApi::class, FlowPreview::class)
class RollListViewModel(application: Application) : AndroidViewModel(application) {

    private val db = AppDatabase.getInstance(application)
    private val rollRepository = RollRepository(db)
    private val appPreferences = AppPreferences(application)

    private val _state = MutableStateFlow(RollListUiState())
    val state: StateFlow<RollListUiState> = _state.asStateFlow()

    private val _events = Channel<RollListEvent>(Channel.BUFFERED)
    val events: Flow<RollListEvent> = _events.receiveAsFlow()

    private val searchQuery = MutableStateFlow("")

    init {
        collectActiveRolls()
        collectFinishedRolls()
        collectArchivedRolls()
    }

    private fun collectActiveRolls() = viewModelScope.launch {
        searchQuery.debounce(300).flatMapLatest { query ->
            rollRepository.searchRollsByStatus(query, RollStatus.ACTIVE.value)
        }.collect { rolls ->
            _state.update { it.copy(activeRolls = rolls, isLoading = false) }
        }
    }

    private fun collectFinishedRolls() = viewModelScope.launch {
        searchQuery.debounce(300).flatMapLatest { query ->
            rollRepository.searchRollsByStatus(query, RollStatus.FINISHED.value)
        }.collect { rolls ->
            _state.update { it.copy(finishedRolls = rolls) }
        }
    }

    private fun collectArchivedRolls() = viewModelScope.launch {
        searchQuery.debounce(300).flatMapLatest { query ->
            rollRepository.searchRollsByStatus(query, RollStatus.ARCHIVED.value)
        }.collect { rolls ->
            _state.update { it.copy(archivedRolls = rolls) }
        }
    }

    // ---------------------------------------------------------------------------
    // User actions
    // ---------------------------------------------------------------------------

    fun onTabSelected(tab: RollListTab) {
        _state.update { it.copy(selectedTab = tab) }
    }

    fun onSearchQueryChanged(query: String) {
        searchQuery.value = query
        _state.update { it.copy(searchQuery = query) }
    }

    fun onAddRollTapped() = viewModelScope.launch {
        _events.send(RollListEvent.NavigateToRollSetup)
    }

    fun onRollCardTapped(rollId: Int) = viewModelScope.launch {
        _events.send(RollListEvent.NavigateToRollJournal(rollId))
    }

    fun onLoadRollSwipedOrLongPressed(roll: Roll) = viewModelScope.launch {
        // Show confirmation sheet — actual load happens in onLoadRollConfirmed
        _events.send(RollListEvent.ShowLoadConfirmation(roll))
    }

    fun onLoadRollConfirmed(roll: Roll) = viewModelScope.launch {
        rollRepository.updateIsLoaded(roll.id, true)
        // If no active roll is currently set, make this the active roll
        if (appPreferences.activeRollId == -1) {
            appPreferences.activeRollId = roll.id
        }
    }

    fun onDeleteTapped(roll: Roll) = viewModelScope.launch {
        _events.send(RollListEvent.ShowDeleteConfirmation(roll))
    }

    fun onDeleteConfirmed(roll: Roll) = viewModelScope.launch {
        // Clear SharedPreferences for this roll
        appPreferences.clearRollPreferences(roll.id)
        // If this was the active roll, clear the active roll selection
        if (appPreferences.activeRollId == roll.id) {
            appPreferences.activeRollId = -1
        }
        rollRepository.deleteRoll(roll)
    }

    fun onArchiveTapped(roll: Roll) = viewModelScope.launch {
        // Archive is a confirmation action — the UI shows a sheet before calling this
        rollRepository.archiveRoll(roll.id)
    }

    fun onUnarchiveTapped(roll: Roll) = viewModelScope.launch {
        rollRepository.unarchiveRoll(roll.id)
    }
}

package com.southsouthwest.framelog.ui.navigation

import kotlinx.serialization.Serializable

// ---------------------------------------------------------------------------
// Type-safe navigation route definitions (Navigation Compose 2.8.0).
// Each object/class corresponds to one back-stack entry.
// Int args default to 0 to represent "new item" (no existing DB row).
// ---------------------------------------------------------------------------

/** App entry point — Quick Screen (frame logging widget target). */
@Serializable
object QuickScreen

/** Gear Library with 5 tabs: Lenses, Bodies, Filters, Film Stocks, Kits. */
@Serializable
object GearLibrary

/** Lens create ([id] = 0) or edit ([id] = existing lens ID). */
@Serializable
data class LensDetail(val id: Int = 0)

/** Camera body create ([id] = 0) or edit ([id] = existing body ID). */
@Serializable
data class CameraBodyDetail(val id: Int = 0)

/** Filter create ([id] = 0) or edit ([id] = existing filter ID). */
@Serializable
data class FilterDetail(val id: Int = 0)

/** Film stock create ([id] = 0) or edit ([id] = existing stock ID). */
@Serializable
data class FilmStockDetail(val id: Int = 0)

/** Kit create ([id] = 0) or edit ([id] = existing kit ID). */
@Serializable
data class KitDetail(val id: Int = 0)

/** Roll list with Active / Finished / Archived tabs. */
@Serializable
object RollList

/** Roll setup / creation form. */
@Serializable
object RollSetup

/**
 * Kit selector — shown from Roll Setup when the user taps "Load from Kit".
 * Returns to Roll Setup via the back stack when a kit is selected.
 */
@Serializable
object KitSelector

/** Roll journal — frame list for a specific roll. */
@Serializable
data class RollJournal(val rollId: Int)

/** Frame detail / edit screen. */
@Serializable
data class FrameDetail(val frameId: Int, val rollId: Int)

/** App settings. */
@Serializable
object Settings

package com.southsouthwest.framelog.data.db.relation

import androidx.room.Embedded
import androidx.room.Relation
import com.southsouthwest.framelog.data.db.entity.Frame
import com.southsouthwest.framelog.data.db.entity.Roll
import com.southsouthwest.framelog.data.db.entity.RollFilter
import com.southsouthwest.framelog.data.db.entity.RollLens

/**
 * A Roll with all its associated lenses, filters, and pre-generated frame slots.
 *
 * Used by the Quick Screen and Roll Journal — one database trip returns everything needed.
 * Queries returning this type must be annotated with @Transaction.
 */
data class RollWithDetails(
    @Embedded val roll: Roll,

    /** Lenses available during this roll, each with full Lens details. */
    @Relation(
        entity = RollLens::class,
        parentColumn = "id",
        entityColumn = "rollId",
    )
    val lenses: List<RollLensWithLens>,

    /** Filters available during this roll, each with full Filter details. */
    @Relation(
        entity = RollFilter::class,
        parentColumn = "id",
        entityColumn = "rollId",
    )
    val filters: List<RollFilterWithFilter>,

    /** All pre-generated frame slots, ordered by frameNumber. */
    @Relation(
        parentColumn = "id",
        entityColumn = "rollId",
    )
    val frames: List<Frame>,
)

package com.southsouthwest.framelog.data.db.dao

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import androidx.room.Transaction
import com.southsouthwest.framelog.data.db.entity.Roll
import com.southsouthwest.framelog.data.db.relation.FrameExport
import com.southsouthwest.framelog.data.db.relation.FilterExportRow
import com.southsouthwest.framelog.data.db.relation.FrameExportRow
import com.southsouthwest.framelog.data.db.relation.RollExport
import com.southsouthwest.framelog.data.db.relation.RollExportRow
import com.southsouthwest.framelog.data.db.relation.RollWithDetails
import kotlinx.coroutines.flow.Flow

@Dao
abstract class RollDao {

    // ---------------------------------------------------------------------------
    // Reads
    // ---------------------------------------------------------------------------

    /**
     * Returns all rolls currently loaded in a camera (isLoaded = true) with full details.
     * The "active roll" for the widget is selected from this list via SharedPreferences.
     * Called on app launch and to populate the Quick Screen header switcher.
     */
    @Transaction
    @Query("SELECT * FROM rolls WHERE isLoaded = 1 ORDER BY loadedAt DESC")
    abstract fun getActiveRolls(): Flow<List<RollWithDetails>>

    /**
     * Returns a specific roll with all its lenses, filters, and frames.
     * Used by the Quick Screen (with rollId from SharedPreferences) and the Roll Journal.
     */
    @Transaction
    @Query("SELECT * FROM rolls WHERE id = :rollId")
    abstract fun getRollById(rollId: Int): Flow<RollWithDetails>

    /**
     * Search rolls by name. Optionally filter by status (pass null for all statuses).
     * Used by the Roll List screen tabs.
     */
    @Query("SELECT * FROM rolls WHERE name LIKE '%' || :query || '%' ORDER BY loadedAt DESC")
    abstract fun searchRolls(query: String): Flow<List<Roll>>

    @Query("SELECT * FROM rolls WHERE name LIKE '%' || :query || '%' AND status = :status ORDER BY loadedAt DESC")
    abstract fun searchRollsByStatus(query: String, status: String): Flow<List<Roll>>

    // ---------------------------------------------------------------------------
    // Writes
    // ---------------------------------------------------------------------------

    /**
     * Inserts a new roll and returns the auto-generated row ID.
     * Not called in isolation — use AppDatabase.createRollWithAssociations() to create
     * a roll atomically with its lenses, filters, and pre-generated frame slots.
     */
    @Insert
    abstract suspend fun insertRoll(roll: Roll): Long

    /** Sets status = finished and records the finish timestamp. */
    @Query("UPDATE rolls SET status = 'finished', finishedAt = :finishedAt WHERE id = :rollId")
    abstract suspend fun finishRoll(rollId: Int, finishedAt: Long)

    /** Sets status = archived. Only valid on finished rolls — enforced by the UI, not the DB. */
    @Query("UPDATE rolls SET status = 'archived' WHERE id = :rollId")
    abstract suspend fun archiveRoll(rollId: Int)

    /** Returns a roll to finished status. A roll cannot return to active via unarchive. */
    @Query("UPDATE rolls SET status = 'finished' WHERE id = :rollId")
    abstract suspend fun unarchiveRoll(rollId: Int)

    /** Updates the isLoaded flag. Called when the user loads or unloads a roll from a camera. */
    @Query("UPDATE rolls SET isLoaded = :isLoaded WHERE id = :rollId")
    abstract suspend fun updateIsLoaded(rollId: Int, isLoaded: Boolean)

    /**
     * Records the timestamp of the last successful export.
     * Not part of a transaction — export timestamp failure is non-critical.
     */
    @Query("UPDATE rolls SET lastExportedAt = :timestamp WHERE id = :rollId")
    abstract suspend fun updateLastExported(rollId: Int, timestamp: Long)

    /**
     * Permanently deletes a roll. Cascades to RollLens, RollFilter, Frame, and FrameFilter
     * records via the database foreign key constraints. This is irreversible.
     * Callers must confirm with the user before invoking.
     */
    @Delete
    abstract suspend fun deleteRoll(roll: Roll)

    // ---------------------------------------------------------------------------
    // Export
    // ---------------------------------------------------------------------------

    /**
     * Returns a fully denormalized RollExport with all frames, lens names, filter names,
     * film stock name, and camera body name resolved to human-readable strings.
     *
     * Implemented as a @Transaction to ensure the snapshot is consistent — no partial
     * writes can occur between the individual queries that assemble this object.
     */
    @Transaction
    open suspend fun getRollForExport(rollId: Int): RollExport {
        val header = queryRollExportHeader(rollId)
        val frameRows = queryFrameExportRows(rollId)
        val frames = frameRows.map { frameRow ->
            val filterRows = queryFilterExportRows(frameRow.id)
            FrameExport(
                frameNumber = frameRow.frameNumber,
                isLogged = frameRow.isLogged,
                loggedAt = frameRow.loggedAt,
                aperture = frameRow.aperture,
                shutterSpeed = frameRow.shutterSpeed,
                lensName = frameRow.lensName,
                lensMake = frameRow.lensMake,
                lensFocalLengthMm = frameRow.lensFocalLengthMm,
                exposureCompensation = frameRow.exposureCompensation,
                filterNames = filterRows.map { it.name },
                filterEvReductions = filterRows.map { it.evReduction },
                lat = frameRow.lat,
                lng = frameRow.lng,
                notes = frameRow.notes,
            )
        }
        return RollExport(
            rollName = header.name,
            filmStockName = header.filmStockName,
            filmStockMake = header.filmStockMake,
            cameraBodyName = header.cameraBodyName,
            cameraBodyMake = header.cameraBodyMake,
            ratedISO = header.ratedISO,
            pushPull = header.pushPull,
            gpsEnabled = header.gpsEnabled,
            loadedAt = header.loadedAt,
            finishedAt = header.finishedAt,
            notes = header.notes,
            frames = frames,
        )
    }

    @Query("""
        SELECT r.name, r.ratedISO, r.pushPull, r.gpsEnabled, r.loadedAt, r.finishedAt, r.notes,
               fs.name AS filmStockName, fs.make AS filmStockMake,
               cb.name AS cameraBodyName, cb.make AS cameraBodyMake
        FROM rolls r
        JOIN film_stocks fs ON r.filmStockId = fs.id
        JOIN camera_bodies cb ON r.cameraBodyId = cb.id
        WHERE r.id = :rollId
    """)
    protected abstract suspend fun queryRollExportHeader(rollId: Int): RollExportRow

    @Query("""
        SELECT f.id, f.frameNumber, f.isLogged, f.loggedAt, f.aperture, f.shutterSpeed,
               f.exposureCompensation, f.lat, f.lng, f.notes,
               l.name AS lensName, l.make AS lensMake, l.focalLengthMm AS lensFocalLengthMm
        FROM frames f
        LEFT JOIN lenses l ON f.lensId = l.id
        WHERE f.rollId = :rollId
        ORDER BY f.frameNumber ASC
    """)
    protected abstract suspend fun queryFrameExportRows(rollId: Int): List<FrameExportRow>

    @Query("""
        SELECT fi.name, fi.evReduction
        FROM frame_filters ff
        JOIN filters fi ON ff.filterId = fi.id
        WHERE ff.frameId = :frameId
    """)
    protected abstract suspend fun queryFilterExportRows(frameId: Int): List<FilterExportRow>
}

