package com.southsouthwest.framelog.ui.rolls

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.viewModelScope
import com.southsouthwest.framelog.data.AppPreferences
import com.southsouthwest.framelog.data.ExportFormat
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.relation.RollWithDetails
import com.southsouthwest.framelog.data.repository.RollRepository
import com.southsouthwest.framelog.ui.util.ExportFormatter
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

// ---------------------------------------------------------------------------
// UiState
// ---------------------------------------------------------------------------

data class RollJournalUiState(
    val roll: RollWithDetails? = null,
    /** The "current" frame number — the frame the Quick Screen is pointing at. */
    val currentFrameNumber: Int = 1,
    val showExportSheet: Boolean = false,
    val selectedExportFormat: ExportFormat = ExportFormat.CSV,
    val isLoading: Boolean = true,
    val isActionInProgress: Boolean = false,
)

// ---------------------------------------------------------------------------
// Events
// ---------------------------------------------------------------------------

sealed class RollJournalEvent {
    data class NavigateToFrameDetail(val frameId: Int, val rollId: Int) : RollJournalEvent()
    /** Emit to show the Finish Roll confirmation sheet. */
    data object ShowFinishRollConfirmation : RollJournalEvent()
    /** Emit to show the Load Roll confirmation sheet. */
    data object ShowLoadRollConfirmation : RollJournalEvent()
    /** Emit to show the Archive confirmation sheet. */
    data object ShowArchiveConfirmation : RollJournalEvent()
    /** Emit to show the Unarchive confirmation sheet. */
    data object ShowUnarchiveConfirmation : RollJournalEvent()
    /** Emit to show the delete danger confirmation. */
    data object ShowDeleteConfirmation : RollJournalEvent()
    /**
     * Emit to hand the formatted export content to the Android share sheet.
     * The UI creates the Intent; ViewModel provides the content and MIME type.
     */
    data class ShareExportContent(
        val content: String,
        val mimeType: String,
        val suggestedFilename: String,
    ) : RollJournalEvent()
    data object NavigateBack : RollJournalEvent()
    data class ShowErrorMessage(val message: String) : RollJournalEvent()
}

// ---------------------------------------------------------------------------
// ViewModel
// ---------------------------------------------------------------------------

class RollJournalViewModel(
    application: Application,
    savedState: SavedStateHandle,
) : AndroidViewModel(application) {

    private val rollId: Int = checkNotNull(savedState["rollId"]) {
        "RollJournalViewModel requires a 'rollId' nav argument"
    }

    private val db = AppDatabase.getInstance(application)
    private val rollRepository = RollRepository(db)
    private val appPreferences = AppPreferences(application)

    private val _state = MutableStateFlow(RollJournalUiState())
    val state: StateFlow<RollJournalUiState> = _state.asStateFlow()

    private val _events = Channel<RollJournalEvent>(Channel.BUFFERED)
    val events: Flow<RollJournalEvent> = _events.receiveAsFlow()

    init {
        viewModelScope.launch {
            rollRepository.getRollById(rollId).collect { rollWithDetails ->
                val currentFrame = appPreferences.getCurrentFrameNumber(rollId)
                _state.update {
                    it.copy(
                        roll = rollWithDetails,
                        currentFrameNumber = currentFrame,
                        isLoading = false,
                    )
                }
            }
        }
    }

    // ---------------------------------------------------------------------------
    // User actions
    // ---------------------------------------------------------------------------

    fun onFrameCardTapped(frameId: Int) = viewModelScope.launch {
        _events.send(RollJournalEvent.NavigateToFrameDetail(frameId, rollId))
    }

    fun onExportTapped() {
        _state.update {
            it.copy(
                showExportSheet = true,
                selectedExportFormat = appPreferences.defaultExportFormat,
            )
        }
    }

    fun onExportFormatSelected(format: ExportFormat) {
        _state.update { it.copy(selectedExportFormat = format) }
    }

    fun onExportDismissed() {
        _state.update { it.copy(showExportSheet = false) }
    }

    fun onExportConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true, showExportSheet = false) }
        try {
            val export = rollRepository.getRollForExport(rollId)
            val rollName = _state.value.roll?.roll?.name ?: "roll_$rollId"
            val format = _state.value.selectedExportFormat

            val (content, mimeType, extension) = when (format) {
                ExportFormat.CSV -> Triple(
                    ExportFormatter.toCsv(export),
                    "text/csv",
                    "csv",
                )
                ExportFormat.JSON -> Triple(
                    ExportFormatter.toJson(export),
                    "application/json",
                    "json",
                )
                ExportFormat.PLAIN_TEXT -> Triple(
                    ExportFormatter.toPlainText(export),
                    "text/plain",
                    "txt",
                )
            }

            val filename = sanitizeFilename(rollName) + ".$extension"
            rollRepository.updateLastExported(rollId, System.currentTimeMillis())

            _events.send(
                RollJournalEvent.ShareExportContent(
                    content = content,
                    mimeType = mimeType,
                    suggestedFilename = filename,
                )
            )
        } catch (e: Exception) {
            _events.send(RollJournalEvent.ShowErrorMessage("Export failed: ${e.message}"))
        } finally {
            _state.update { it.copy(isActionInProgress = false) }
        }
    }

    // ---------------------------------------------------------------------------
    // Roll state transitions (confirmation is handled by the UI before calling these)
    // ---------------------------------------------------------------------------

    fun onLoadRollTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowLoadRollConfirmation)
    }

    fun onLoadRollConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.updateIsLoaded(rollId, true)
        if (appPreferences.activeRollId == -1) {
            appPreferences.activeRollId = rollId
        }
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onFinishRollTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowFinishRollConfirmation)
    }

    fun onFinishRollConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.finishRoll(rollId, System.currentTimeMillis())
        // Unload the roll — a finished roll is no longer in a camera
        rollRepository.updateIsLoaded(rollId, false)
        // If this was the active roll, clear the selection
        if (appPreferences.activeRollId == rollId) {
            appPreferences.activeRollId = -1
        }
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onArchiveTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowArchiveConfirmation)
    }

    fun onArchiveConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.archiveRoll(rollId)
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onUnarchiveTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowUnarchiveConfirmation)
    }

    fun onUnarchiveConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.unarchiveRoll(rollId)
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onDeleteTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowDeleteConfirmation)
    }

    fun onDeleteConfirmed() = viewModelScope.launch {
        val roll = _state.value.roll?.roll ?: return@launch
        appPreferences.clearRollPreferences(rollId)
        if (appPreferences.activeRollId == rollId) {
            appPreferences.activeRollId = -1
        }
        rollRepository.deleteRoll(roll)
        _events.send(RollJournalEvent.NavigateBack)
    }

    // ---------------------------------------------------------------------------
    // Helpers
    // ---------------------------------------------------------------------------

    private fun sanitizeFilename(name: String): String =
        name.replace(Regex("[^a-zA-Z0-9._-]"), "_")
}

package com.southsouthwest.framelog.data

import android.content.Context
import androidx.core.content.edit

private const val PREFS_NAME = "framelog_prefs"

// Global keys
private const val KEY_ONBOARDING_COMPLETE = "onboarding_complete"
private const val KEY_ACTIVE_ROLL_ID = "active_roll_id"
private const val KEY_EXTRA_FRAMES_PER_ROLL = "extra_frames_per_roll"
private const val KEY_GPS_PRECISION = "gps_precision"
private const val KEY_DEFAULT_EXPORT_FORMAT = "default_export_format"
private const val KEY_APP_THEME = "app_theme"
private const val KEY_ACCESSIBLE_COLOR_MODE = "accessible_color_mode"
private const val KEY_TIP_JAR_PROMPT_SHOWN = "tip_jar_prompt_shown"

// Per-roll keys
private fun keyCurrentFrame(rollId: Int) = "current_frame_$rollId"
private fun keyMruFilters(rollId: Int) = "mru_filters_$rollId"

/**
 * Thin wrapper around SharedPreferences for all app configuration.
 *
 * All photography data lives in Room. This class holds:
 *   - The active roll ID (which loaded roll drives the widget and Quick Screen)
 *   - Onboarding and session state
 *   - User preferences (extra frames, GPS precision, export format, theme)
 *   - Per-roll ephemeral state (current frame pointer, MRU filter chip order)
 *
 * Not a singleton — instantiate wherever needed with an Application or activity Context.
 */
class AppPreferences(context: Context) {

    private val prefs = context.applicationContext
        .getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    // ---------------------------------------------------------------------------
    // Onboarding
    // ---------------------------------------------------------------------------

    /** True after the user completes or skips onboarding. Gates the coach mark flow. */
    var onboardingComplete: Boolean
        get() = prefs.getBoolean(KEY_ONBOARDING_COMPLETE, false)
        set(value) = prefs.edit { putBoolean(KEY_ONBOARDING_COMPLETE, value) }

    // ---------------------------------------------------------------------------
    // Active roll selection
    // ---------------------------------------------------------------------------

    /**
     * The roll ID currently selected for the widget and Quick Screen.
     * -1 means no roll is selected (no loaded rolls exist).
     *
     * Updated by:
     *   - RollSetup when "Create & Load Roll" is tapped (if no other loaded roll exists)
     *   - Quick Screen switch-roll sheet when user selects a different loaded roll
     *   - Automatically when the active roll is finished or unloaded (falls back to next loaded roll)
     */
    var activeRollId: Int
        get() = prefs.getInt(KEY_ACTIVE_ROLL_ID, -1)
        set(value) = prefs.edit { putInt(KEY_ACTIVE_ROLL_ID, value) }

    // ---------------------------------------------------------------------------
    // Shooting defaults
    // ---------------------------------------------------------------------------

    /**
     * Extra frames appended beyond the film stock's defaultFrameCount at roll creation.
     * The extra frames account for leader frames and the slight over-capacity of most film.
     * Default 2. Editable in Settings.
     */
    var extraFramesPerRoll: Int
        get() = prefs.getInt(KEY_EXTRA_FRAMES_PER_ROLL, 2)
        set(value) = prefs.edit { putInt(KEY_EXTRA_FRAMES_PER_ROLL, value) }

    var gpsPrecision: GpsPrecision
        get() = GpsPrecision.fromKey(prefs.getString(KEY_GPS_PRECISION, GpsPrecision.HIGH.key)!!)
        set(value) = prefs.edit { putString(KEY_GPS_PRECISION, value.key) }

    var defaultExportFormat: ExportFormat
        get() = ExportFormat.fromKey(
            prefs.getString(KEY_DEFAULT_EXPORT_FORMAT, ExportFormat.CSV.key)!!
        )
        set(value) = prefs.edit { putString(KEY_DEFAULT_EXPORT_FORMAT, value.key) }

    // ---------------------------------------------------------------------------
    // Appearance
    // ---------------------------------------------------------------------------

    var appTheme: AppTheme
        get() = AppTheme.fromKey(prefs.getString(KEY_APP_THEME, AppTheme.SYSTEM.key)!!)
        set(value) = prefs.edit { putString(KEY_APP_THEME, value.key) }

    /**
     * When true, color-coded elements (e.g. long-exposure shutter speeds) use a supplementary
     * indicator (underline or suffix) in addition to or instead of color alone.
     */
    var accessibleColorMode: Boolean
        get() = prefs.getBoolean(KEY_ACCESSIBLE_COLOR_MODE, false)
        set(value) = prefs.edit { putBoolean(KEY_ACCESSIBLE_COLOR_MODE, value) }

    // ---------------------------------------------------------------------------
    // Tip jar
    // ---------------------------------------------------------------------------

    /**
     * True once the one-time 5-rolls-logged prompt has been shown.
     * The tip jar button in Settings remains visible regardless of this flag.
     */
    var tipJarPromptShown: Boolean
        get() = prefs.getBoolean(KEY_TIP_JAR_PROMPT_SHOWN, false)
        set(value) = prefs.edit { putBoolean(KEY_TIP_JAR_PROMPT_SHOWN, value) }

    // ---------------------------------------------------------------------------
    // Per-roll state
    // ---------------------------------------------------------------------------

    /**
     * The current frame number for a roll (1-based). This is the frame the Quick Screen
     * and widget are pointing at for the next log operation.
     *
     * Initialized to 1 when a roll is first loaded. Updated after each successful frame log
     * (advances to the next unlogged frame) and by the frame pointer stepper.
     */
    fun getCurrentFrameNumber(rollId: Int): Int =
        prefs.getInt(keyCurrentFrame(rollId), 1)

    fun setCurrentFrameNumber(rollId: Int, frameNumber: Int) =
        prefs.edit { putInt(keyCurrentFrame(rollId), frameNumber) }

    /**
     * Ordered list of up to 4 most recently toggled filter IDs for a roll.
     * Drives the filter chip row on the Quick Screen and Frame Detail screen.
     * Order: most recently used first (index 0).
     */
    fun getMruFilterIds(rollId: Int): List<Int> {
        val raw = prefs.getString(keyMruFilters(rollId), "") ?: ""
        if (raw.isBlank()) return emptyList()
        return raw.split(",").mapNotNull { it.toIntOrNull() }
    }

    fun setMruFilterIds(rollId: Int, filterIds: List<Int>) {
        prefs.edit { putString(keyMruFilters(rollId), filterIds.take(4).joinToString(",")) }
    }

    /**
     * Promotes [filterId] to the front of the MRU list for [rollId], keeping at most 4 entries.
     * Called whenever the user toggles a filter on the Quick Screen or Frame Detail screen.
     */
    fun promoteFilterInMru(rollId: Int, filterId: Int) {
        val current = getMruFilterIds(rollId).toMutableList()
        current.remove(filterId)
        current.add(0, filterId)
        setMruFilterIds(rollId, current)
    }

    /**
     * Removes all per-roll keys for the given roll. Called when a roll is deleted.
     */
    fun clearRollPreferences(rollId: Int) {
        prefs.edit {
            remove(keyCurrentFrame(rollId))
            remove(keyMruFilters(rollId))
        }
    }
}

// ---------------------------------------------------------------------------
// Preference enums
// ---------------------------------------------------------------------------

enum class GpsPrecision(val key: String) {
    HIGH("high"),
    BATTERY_SAVER("battery_saver");

    companion object {
        fun fromKey(key: String) = entries.firstOrNull { it.key == key } ?: HIGH
    }
}

enum class ExportFormat(val key: String) {
    CSV("csv"),
    JSON("json"),
    PLAIN_TEXT("plain_text");

    companion object {
        fun fromKey(key: String) = entries.firstOrNull { it.key == key } ?: CSV
    }
}

enum class AppTheme(val key: String) {
    LIGHT("light"),
    DARK("dark"),
    SYSTEM("system");

    companion object {
        fun fromKey(key: String) = entries.firstOrNull { it.key == key } ?: SYSTEM
    }
}

package com.southsouthwest.framelog.data.db.relation

import androidx.room.Embedded
import androidx.room.Relation
import com.southsouthwest.framelog.data.db.entity.Lens
import com.southsouthwest.framelog.data.db.entity.RollLens

/** A RollLens join record together with the full Lens details. */
data class RollLensWithLens(
    @Embedded val rollLens: RollLens,
    @Relation(parentColumn = "lensId", entityColumn = "id")
    val lens: Lens,
)

package com.southsouthwest.framelog.ui.util

import com.southsouthwest.framelog.data.db.entity.ApertureIncrements
import com.southsouthwest.framelog.data.db.entity.ShutterIncrements

/**
 * Generates valid aperture and shutter speed value lists for stepper controls.
 *
 * All values use the canonical storage format (same strings stored in the database):
 *   Apertures: "f/1.4", "f/8", "f/11" etc.
 *   Shutter speeds: "B", "30s", "1s", "1/125", "1/1000" etc.
 *
 * Lists are ordered slow→fast (shutter) or wide→narrow (aperture) so that stepping
 * "up" always increases exposure.
 */
object ExposureValues {

    // ---------------------------------------------------------------------------
    // Shutter speed sequences
    // ---------------------------------------------------------------------------

    // Full stops: B + 19 stops from 30s to 1/8000
    private val SHUTTER_FULL = listOf(
        "B",
        "30s", "15s", "8s", "4s", "2s", "1s",
        "1/2", "1/4", "1/8", "1/15", "1/30", "1/60",
        "1/125", "1/250", "1/500", "1/1000", "1/2000", "1/4000", "1/8000",
    )

    // Half stops: same range with intermediate values added
    private val SHUTTER_HALF = listOf(
        "B",
        "30s", "20s", "15s", "10s", "8s", "6s", "4s", "3s", "2s", "1.5s", "1s",
        "1/1.5", "1/2", "1/3", "1/4", "1/6", "1/8", "1/10", "1/15", "1/20",
        "1/30", "1/45", "1/60", "1/90", "1/125", "1/180", "1/250", "1/350",
        "1/500", "1/750", "1/1000", "1/1500", "1/2000", "1/3000", "1/4000",
        "1/6000", "1/8000",
    )

    // Third stops: standard photographic values at 1/3 stop spacing
    private val SHUTTER_THIRD = listOf(
        "B",
        "30s", "25s", "20s", "15s", "13s", "10s", "8s", "6s", "5s", "4s", "3s",
        "2.5s", "2s", "1.6s", "1.3s", "1s",
        "1/1.3", "1/1.6", "1/2", "1/2.5", "1/3", "1/4", "1/5", "1/6",
        "1/8", "1/10", "1/13", "1/15", "1/20", "1/25", "1/30", "1/40", "1/50",
        "1/60", "1/80", "1/100", "1/125", "1/160", "1/200", "1/250", "1/320", "1/400",
        "1/500", "1/640", "1/800", "1/1000", "1/1250", "1/1600", "1/2000", "1/2500",
        "1/3200", "1/4000", "1/5000", "1/6400", "1/8000",
    )

    /**
     * Returns the complete shutter speed list for the given increment type,
     * ordered slowest → fastest (B first, 1/8000 last).
     */
    fun shutterSpeeds(increments: ShutterIncrements): List<String> = when (increments) {
        ShutterIncrements.FULL -> SHUTTER_FULL
        ShutterIncrements.HALF -> SHUTTER_HALF
        ShutterIncrements.THIRD -> SHUTTER_THIRD
    }

    /**
     * Returns the human-readable display string for a stored shutter speed value.
     *
     * Convention from the DESIGN decisions doc:
     *   "1/125" → "125"  (drop the "1/" — implied by context)
     *   "2s"    → "2s"   (keep the s-suffix for whole seconds)
     *   "B"     → "B"
     */
    fun shutterDisplayValue(stored: String): String = when {
        stored == "B" -> "B"
        stored.endsWith("s") -> stored
        stored.startsWith("1/") -> stored.removePrefix("1/")
        else -> stored // e.g. "1/1.5" keeps as-is if doesn't match above
    }

    /**
     * Returns true if this shutter speed value should render in the accent color.
     * Whole-second values and bulb are "long exposure" by convention (red numbers on
     * classic cameras like the Canon AE-1).
     */
    fun isLongExposure(stored: String): Boolean =
        stored == "B" || stored.endsWith("s")

    // ---------------------------------------------------------------------------
    // Aperture sequences
    // ---------------------------------------------------------------------------

    // Full stops: f/1 through f/64
    private val APERTURE_FULL = listOf(
        1.0f, 1.4f, 2.0f, 2.8f, 4.0f, 5.6f, 8.0f, 11.0f, 16.0f, 22.0f, 32.0f, 45.0f, 64.0f,
    )

    // Half stops: intermediate values added between full stops
    private val APERTURE_HALF = listOf(
        1.0f, 1.2f, 1.4f, 1.7f, 2.0f, 2.4f, 2.8f, 3.3f, 4.0f, 4.8f, 5.6f, 6.7f,
        8.0f, 9.5f, 11.0f, 13.0f, 16.0f, 19.0f, 22.0f, 27.0f, 32.0f,
    )

    // Third stops: standard photographic values at 1/3 stop spacing
    private val APERTURE_THIRD = listOf(
        1.0f, 1.1f, 1.2f, 1.4f, 1.6f, 1.8f, 2.0f, 2.2f, 2.5f, 2.8f, 3.2f, 3.5f,
        4.0f, 4.5f, 5.0f, 5.6f, 6.3f, 7.1f, 8.0f, 9.0f, 10.0f, 11.0f, 13.0f, 14.0f,
        16.0f, 18.0f, 20.0f, 22.0f, 25.0f, 29.0f, 32.0f,
    )

    /**
     * Returns valid aperture strings for a lens, bounded by [maxAperture] (widest) and
     * [minAperture] (narrowest), using the lens's [increments] type.
     *
     * Ordered widest → narrowest (f/1.4 first, f/22 last) — "up" step = wider = more exposure.
     *
     * A small epsilon (0.05) is used in the bounds check to handle floating-point edge cases
     * where lens.maxAperture = 1.4f might not exactly match the list value 1.4f.
     */
    fun apertures(
        maxAperture: Float,
        minAperture: Float,
        increments: ApertureIncrements,
    ): List<String> {
        val all = when (increments) {
            ApertureIncrements.FULL -> APERTURE_FULL
            ApertureIncrements.HALF -> APERTURE_HALF
            ApertureIncrements.THIRD -> APERTURE_THIRD
        }
        return all
            .filter { it >= maxAperture - 0.05f && it <= minAperture + 0.05f }
            .map { formatAperture(it) }
    }

    /**
     * Formats a Float aperture value to the canonical "f/X" storage string.
     * Integer values omit the decimal point: 8.0f → "f/8", 1.4f → "f/1.4".
     */
    fun formatAperture(value: Float): String =
        if (value == value.toLong().toFloat()) "f/${value.toLong()}" else "f/$value"

    /**
     * Parses a canonical "f/X" string back to a Float for bounds comparison.
     * Returns null if the string is malformed.
     */
    fun parseAperture(stored: String): Float? =
        stored.removePrefix("f/").toFloatOrNull()

    // ---------------------------------------------------------------------------
    // Exposure compensation
    // ---------------------------------------------------------------------------

    /**
     * Valid exposure compensation values in 1/3 stop increments from -3.0 to +3.0 EV.
     * Null is not in this list — the ViewModel handles null separately as "no EC applied".
     */
    val exposureCompensationValues: List<Float> = buildList {
        // Generate -3.0, -2.67, -2.33 … 0 … 2.33, 2.67, 3.0
        // Use integer arithmetic to avoid float accumulation error.
        for (thirds in -9..9) {
            add(thirds / 3.0f)
        }
    }

    /**
     * Formats an EC float for display, e.g. 0.0 → "0", 0.333 → "+⅓", -1.0 → "-1".
     * Uses vulgar fractions for third-stop values for a clean camera-dial aesthetic.
     */
    fun formatExposureCompensation(value: Float): String {
        val thirds = (value * 3).toInt()
        val wholePart = thirds / 3
        val remainder = thirds % 3
        val sign = if (value > 0f) "+" else if (value < 0f) "-" else ""
        val absWhole = Math.abs(wholePart)
        val absFrac = Math.abs(remainder)
        return when {
            thirds == 0 -> "0"
            absFrac == 0 -> "$sign$absWhole"
            absWhole == 0 -> "$sign${fraction(absFrac)}"
            else -> "$sign$absWhole${fraction(absFrac)}"
        }
    }

    private fun fraction(thirds: Int): String = when (thirds) {
        1 -> "⅓"
        2 -> "⅔"
        else -> ""
    }
}

